// assumes your message text is in $json.output
let text = $json.output || "";

// Replace lines that start with "- " into "▪️ "
text = text.replace(/(^|\n)-\s+/g, "$1▪️ ");

// Optional: also fix numbered lists like "1. " into bullets (comment out if you don't want)
text = text.replace(/(^|\n)\d+\.\s+/g, "$1▪️ ");

return [{ ...$json, output: text }];
